@page "/"
@using SkiaSharp
@using SkiaSharp.Views.Blazor

<h1>SkiaSharp CanvasSize Test</h1>

<SKCanvasView @ref="canvasView" OnPaintSurface="OnPaintSurface" />

<p>Canvas Size: @canvasWidth x @canvasHeight</p>

@code {
    private SKCanvasView? canvasView;
    private float canvasWidth;
    private float canvasHeight;

    private void OnPaintSurface(SKPaintSurfaceEventArgs e)
    {
        // Try to access CanvasSize property (the feature requested in #1911)
        var size = canvasView!.CanvasSize;
        canvasWidth = size.Width;
        canvasHeight = size.Height;

        var canvas = e.Surface.Canvas;
        canvas.Clear(SKColors.CornflowerBlue);
    }
}

